sql:
SELECT SUM(earnings) 
FROM box_office
WHERE movie_id = (SELECT movie_id FROM movies WHERE name = 'Avatar');

SELECT name AS Most_Popular_Movie, score AS Average_Score, votes AS Total_Votes
FROM movies
WHERE votes = (SELECT MAX(votes) FROM movies);

SELECT name 
FROM movies 
WHERE score > 8.5;

SELECT T1.writer_name, T2.name AS movie_name
FROM writers AS T1
INNER JOIN movies AS T2 ON T1.writer_id = T2.writer_id;

SELECT name 
FROM movies 
WHERE movie_id = 0;
